1	<!doctype html>
2	<html lang="en">
3	<head>
4	<meta charset="utf-8" />
5	<meta name="viewport" content="width=device-width, initial-scale=1" />
6	<title>Deal-flow Matchmaker</title>
7	<style>
8	  :root {
9	    --bg: #0d1117; --panel: #161b22; --border: #30363d; --fg: #e6edf3;
10	    --muted: #8b949e; --accent: #2f81f7; --good: #3fb950; --warn: #d29922;
11	    --bad: #f85149; --chip: #21262d;
12	  }
13	  * { box-sizing: border-box; }
14	  body { margin: 0; font: 14px/1.5 -apple-system, "Segoe UI", Roboto, sans-serif;
15	    background: var(--bg); color: var(--fg); }
16	  header { display: flex; align-items: center; gap: 16px; padding: 12px 20px;
17	    border-bottom: 1px solid var(--border); background: var(--panel); position: sticky; top: 0; z-index: 5; }
18	  header h1 { font-size: 16px; margin: 0; font-weight: 600; }
19	  header .spacer { flex: 1; }
20	  .stat { font-size: 12px; color: var(--muted); }
21	  .stat b { color: var(--fg); font-size: 14px; }
22	  button { background: var(--accent); color: #fff; border: 0; border-radius: 6px;
23	    padding: 7px 12px; font-size: 13px; cursor: pointer; }
24	  button:hover { filter: brightness(1.1); }
25	  button.ghost { background: var(--chip); color: var(--fg); border: 1px solid var(--border); }
26	  .layout { display: grid; grid-template-columns: 280px 1fr 320px; gap: 0; height: calc(100vh - 53px); }
27	  .col { overflow-y: auto; padding: 14px; }
28	  .col.left { border-right: 1px solid var(--border); }
29	  .col.right { border-left: 1px solid var(--border); background: var(--panel); }
30	  h2 { font-size: 11px; text-transform: uppercase; letter-spacing: .06em; color: var(--muted);
31	    margin: 0 0 8px; font-weight: 600; }
32	  .section { margin-bottom: 22px; }
33	  .ent { padding: 7px 9px; border-radius: 6px; cursor: pointer; display: flex; justify-content: space-between;
34	    align-items: center; gap: 6px; }
35	  .ent:hover { background: var(--chip); }
36	  .ent.sel { background: #1f6feb33; outline: 1px solid var(--accent); }
37	  .ent .nm { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
38	  .ent.partner { cursor: default; opacity: .8; }
39	  .ent.partner:hover { background: transparent; }
40	  .badge { font-size: 10px; padding: 1px 6px; border-radius: 10px; background: var(--chip);
41	    color: var(--muted); white-space: nowrap; }
42	  .badge.ready { color: var(--good); } .badge.seeded { color: var(--warn); }
43	  .mc { font-size: 11px; color: var(--accent); }
44	  .card { background: var(--panel); border: 1px solid var(--border); border-radius: 8px;
45	    padding: 14px; margin-bottom: 12px; }
46	  .match-head { display: flex; align-items: baseline; gap: 10px; }
47	  .match-head .score { font-size: 20px; font-weight: 700; color: var(--accent); }
48	  .match-head .pname { font-size: 15px; font-weight: 600; }
49	  .kv { display: flex; gap: 12px; flex-wrap: wrap; margin: 6px 0; font-size: 12px; color: var(--muted); }
50	  .rationale { margin: 8px 0; }
51	  .rationale .lbl { font-size: 10px; text-transform: uppercase; color: var(--muted); letter-spacing: .05em; }
52	  details { margin-top: 8px; }
53	  summary { cursor: pointer; color: var(--accent); font-size: 12px; }
54	  pre { white-space: pre-wrap; word-wrap: break-word; background: var(--bg); border: 1px solid var(--border);
55	    border-radius: 6px; padding: 10px; font: 12px/1.5 ui-monospace, Menlo, monospace; margin: 6px 0; max-height: 320px; overflow: auto; }
56	  .status-ready { color: var(--good); } .status-ranked { color: var(--warn); }
57	  table { width: 100%; border-collapse: collapse; font-size: 12px; }
58	  td, th { text-align: left; padding: 3px 4px; border-bottom: 1px solid var(--border); }
59	  th { color: var(--muted); font-weight: 500; }
60	  .ev { font-size: 12px; padding: 5px 0; border-bottom: 1px solid var(--border); display: flex; gap: 8px; }
61	  .ev .k { font-weight: 600; }
62	  .ev .t { color: var(--muted); margin-left: auto; white-space: nowrap; }
63	  .kind-Verified, .kind-DraftReady { color: var(--good); }
64	  .kind-VerifyRejected, .kind-DraftDeadLettered { color: var(--bad); }
65	  .kind-MatchesRanked, .kind-FilterCompleted { color: var(--accent); }
66	  .empty { color: var(--muted); font-style: italic; padding: 20px 0; }
67	  .dot { display: inline-block; width: 8px; height: 8px; border-radius: 50%; margin-right: 5px; }
68	  .dot.busy { background: var(--warn); } .dot.idle { background: var(--good); }
69	  .dot.dead { background: var(--bad); } .dot.starting { background: var(--accent); }
70	  .costbar { height: 6px; background: var(--accent); border-radius: 3px; }
71	</style>
72	</head>
73	<body>
74	<header>
75	  <h1>Deal-flow Matchmaker</h1>
76	  <div class="stat">LLM cost <b id="hdr-cost">—</b></div>
77	  <div class="stat">/entity <b id="hdr-cpe">—</b></div>
78	  <div class="stat">/match <b id="hdr-cpm">—</b></div>
79	  <div class="spacer"></div>
80	  <div class="stat" id="pulse">live</div>
81	  <button id="run-btn" class="ghost">Run outreach (all)</button>
82	</header>
83	
84	<div class="layout">
85	  <div class="col left">
86	    <div class="section">
87	      <h2>Startups</h2>
88	      <div id="startups"></div>
89	    </div>
90	    <div class="section">
91	      <h2>Partners</h2>
92	      <div id="partners"></div>
93	    </div>
94	  </div>
95	
96	  <div class="col mid">
97	    <div id="detail"><div class="empty">Select a startup to see its ranked matches, rationale and drafts.</div></div>
98	  </div>
99	
100	  <div class="col right">
101	    <div class="section">
102	      <h2>LLM Cost</h2>
103	      <div id="costs"></div>
104	    </div>
105	    <div class="section">
106	      <h2>Pool &amp; Queue Health</h2>
107	      <div id="health"></div>
108	    </div>
109	    <div class="section">
110	      <h2>Event Stream</h2>
111	      <div id="events"></div>
112	    </div>
113	  </div>
114	</div>
115	
116	<script>
117	const $ = (id) => document.getElementById(id);
118	let selected = null;
119	
120	async function j(path, opts) {
121	  const r = await fetch(path, opts);
122	  if (!r.ok) throw new Error(path + " " + r.status);
123	  return r.json();
124	}
125	const usd = (v) => (v == null ? "—" : "$" + Number(v).toFixed(4));
126	const short = (t) => t ? new Date(t).toLocaleTimeString() : "";
127	
128	async function loadEntities() {
129	  const ents = await j("/entities");
130	  const startups = ents.filter(e => e.type === "startup");
131	  const partners = ents.filter(e => e.type !== "startup");
132	  $("startups").innerHTML = startups.length ? startups.map(e => `
133	    <div class="ent ${selected === e.id ? "sel" : ""}" data-id="${e.id}">
134	      <span class="nm">${e.name}</span>
135	      ${e.match_count ? `<span class="mc">${e.match_count}★</span>` : ""}
136	      <span class="badge ${e.status}">${e.status}</span>
137	    </div>`).join("") : `<div class="empty">No startups onboarded yet.</div>`;
138	  $("partners").innerHTML = partners.map(e => `
139	    <div class="ent partner">
140	      <span class="nm">${e.name}</span>
141	      <span class="badge">${e.type.replace("_"," ")}</span>
142	    </div>`).join("") || `<div class="empty">No partners.</div>`;
143	  document.querySelectorAll(".ent[data-id]").forEach(el =>
144	    el.onclick = () => { selected = el.dataset.id; loadEntities(); loadDetail(); });
145	}
146	
147	async function loadDetail() {
148	  if (!selected) return;
149	  const [ent, matches] = await Promise.all([
150	    j("/entities/" + encodeURIComponent(selected)),
151	    j("/matches?startup_id=" + encodeURIComponent(selected)),
152	  ]);
153	  const p = ent.profile || {};
154	  const desc = (p.description && (p.description.value || p.description)) || "";
155	  let html = `<div class="card">
156	    <div class="match-head"><span class="pname">${ent.name}</span>
157	      <span class="badge ${ent.status}">${ent.status}</span></div>
158	    <div class="kv">${(p.sectors || p.normalized && p.normalized.sectors || []).map ?
159	      (p.sectors || []).map(s => `<span class="badge">${typeof s==="string"?s:JSON.stringify(s)}</span>`).join("") : ""}</div>
160	    ${desc ? `<div class="rationale">${typeof desc === "string" ? desc : ""}</div>` : ""}
161	  </div>`;
162	
163	  if (!matches.length) {
164	    html += `<div class="empty">No matches yet. Trigger a run, then start the supervisor with --drain.</div>`;
165	  } else {
166	    html += `<h2>Ranked matches (${matches.length})</h2>`;
167	    html += matches.map(m => `
168	      <div class="card">
169	        <div class="match-head">
170	          <span class="score">${m.composite != null ? Math.round(m.composite) : "?"}</span>
171	          <span class="pname">${m.partner_name || m.partner_id}</span>
172	          <span class="badge">${(m.partner_type||"").replace("_"," ")}</span>
173	          <span class="badge status-${m.status}">${m.status}</span>
174	        </div>
175	        <div class="kv">
176	          <span>semantic ${m.semantic != null ? Number(m.semantic).toFixed(2) : "—"}</span>
177	          <span>sector overlap ${m.sector_overlap != null ? Number(m.sector_overlap).toFixed(2) : "—"}</span>
178	        </div>
179	        ${m.rationale_en ? `<div class="rationale"><div class="lbl">Rationale (EN)</div>${m.rationale_en}</div>` : ""}
180	        ${m.rationale_vi ? `<div class="rationale"><div class="lbl">Rationale (VI)</div>${m.rationale_vi}</div>` : ""}
181	        ${m.draft_en ? `<details><summary>Draft email (EN)</summary><pre>${escapeHtml(m.draft_en)}</pre></details>` : ""}
182	        ${m.draft_vi ? `<details><summary>Draft email (VI)</summary><pre>${escapeHtml(m.draft_vi)}</pre></details>` : ""}
183	      </div>`).join("");
184	  }
185	  $("detail").innerHTML = html;
186	}
187	
188	function escapeHtml(s) {
189	  return String(s).replace(/[&<>]/g, c => ({"&":"&amp;","<":"&lt;",">":"&gt;"}[c]));
190	}
191	
192	async function loadCosts() {
193	  const c = await j("/costs");
194	  $("hdr-cost").textContent = usd(c.total.cost_usd);
195	  $("hdr-cpe").textContent = usd(c.cost_per_ready_entity);
196	  $("hdr-cpm").textContent = usd(c.cost_per_match);
197	  const max = Math.max(1e-9, ...c.by_agent.map(a => a.cost_usd));
198	  $("costs").innerHTML = `
199	    <table><tr><th>agent</th><th>turns</th><th>cost</th></tr>
200	    ${c.by_agent.map(a => `<tr><td>${a.agent}<br>
201	      <div class="costbar" style="width:${Math.round(100*a.cost_usd/max)}%"></div></td>
202	      <td>${a.turns}</td><td>${usd(a.cost_usd)}</td></tr>`).join("")}
203	    </table>
204	    <div class="stat" style="margin-top:8px">${c.total.tokens_in.toLocaleString()} in /
205	      ${c.total.tokens_out.toLocaleString()} out tokens · ${c.total.turns} turns</div>`;
206	}
207	
208	async function loadHealth() {
209	  const m = await j("/metrics");
210	  const w = m.workers || {};
211	  const wchips = Object.keys(w).length ? Object.entries(w).map(([s,n]) =>
212	    `<span class="badge"><span class="dot ${s}"></span>${s} ${n}</span>`).join(" ")
213	    : `<span class="empty">no workers registered</span>`;
214	  const jobs = m.jobs_by_stage_status || [];
215	  $("health").innerHTML = `
216	    <div style="margin-bottom:8px">${wchips}</div>
217	    <div class="kv">
218	      <span>ready <b>${m.queue.ready}</b></span>
219	      <span>leased <b>${m.queue.leased}</b></span>
220	      <span>dead-letter <b>${m.queue.dead_letter}</b></span>
221	    </div>
222	    <table style="margin-top:6px"><tr><th>stage</th><th>status</th><th>n</th></tr>
223	    ${jobs.map(x => `<tr><td>${x.stage}</td><td>${x.status}</td><td>${x.n}</td></tr>`).join("")}
224	    </table>`;
225	}
226	
227	async function loadEvents() {
228	  const evs = await j("/events?limit=20");
229	  $("events").innerHTML = evs.length ? evs.map(e => `
230	    <div class="ev">
231	      <span class="k kind-${e.kind}">${e.kind}</span>
232	      <span class="t">${short(e.created_at)}</span>
233	    </div>`).join("") : `<div class="empty">No events yet.</div>`;
234	}
235	
236	async function refresh() {
237	  try {
238	    await Promise.all([loadEntities(), loadCosts(), loadHealth(), loadEvents()]);
239	    if (selected) await loadDetail();
240	    $("pulse").textContent = "live · " + new Date().toLocaleTimeString();
241	    $("pulse").style.color = "var(--good)";
242	  } catch (e) {
243	    $("pulse").textContent = "error: " + e.message;
244	    $("pulse").style.color = "var(--bad)";
245	  }
246	}
247	
248	$("run-btn").onclick = async () => {
249	  $("run-btn").disabled = true;
250	  try {
251	    const r = await j("/runs", {
252	      method: "POST", headers: {"Content-Type": "application/json"},
253	      body: JSON.stringify({all: true}),
254	    });
255	    $("pulse").textContent = `triggered ${r.count} saga(s) · ${r.trace_id}`;
256	  } catch (e) { $("pulse").textContent = "run failed: " + e.message; }
257	  finally { $("run-btn").disabled = false; refresh(); }
258	};
259	
260	refresh();
261	setInterval(refresh, 3000);
262	</script>
263	</body>
264	</html>
