// ---- generic profile rendering (provenance-aware) --------------------------
const RESERVED = new Set(
  ["seed", "normalized", "relationships", "collection_summary", "entity_type", "edges"]);

function isProv(v) {
  return v && typeof v === "object" && !Array.isArray(v) && ("value" in v);
}
function pick(v) {  // unwrap {value,...} → value, else identity
  return isProv(v) ? v.value : v;
}
function provMeta(v) {
  let s = "";
  if (v.source_url) s += ` <a class="src" href="${escapeAttr(v.source_url)}" target="_blank" rel="noopener">source ↗</a>`;
  if (v.confidence != null) s += ` <span class="conf">${typeof v.confidence === "number" ? v.confidence.toFixed(2) : escapeHtml(v.confidence)}</span>`;
  return s;
}
function fmtScalar(v) {
  if (v == null || v === "") return "";
  return escapeHtml(typeof v === "object" ? JSON.stringify(v) : v);
}
function valBody(v) {
  if (Array.isArray(v))
    return v.map(x => typeof x === "object" && x !== null
      ? escapeHtml(JSON.stringify(x)) : `<span class="badge">${escapeHtml(x)}</span>`).join(" ");
  return fmtScalar(v);
}
function renderField(key, val) {
  if (val == null || val === "") return "";
  if (isProv(val))
    return `<div class="fld"><span class="fk">${escapeHtml(key)}</span>
      <span class="fv">${valBody(val.value)}${provMeta(val)}</span></div>`;
  if (Array.isArray(val)) {
    if (!val.length) return "";
    if (val.every(x => typeof x !== "object" || x === null))
      return `<div class="fld"><span class="fk">${escapeHtml(key)}</span>
        <span class="fv chips">${val.map(x => `<span class="badge">${escapeHtml(x)}</span>`).join("")}</span></div>`;
    return `<div class="fld nested"><span class="fk">${escapeHtml(key)}</span>
      <div class="nest">${val.map((x, i) => renderField("#" + (i + 1), x)).join("")}</div></div>`;
  }
  if (typeof val === "object") {
    const rows = Object.entries(val).map(([k, v]) => renderField(k, v)).join("");
    return rows ? `<div class="fld nested"><span class="fk">${escapeHtml(key)}</span>
      <div class="nest">${rows}</div></div>` : "";
  }
  return `<div class="fld"><span class="fk">${escapeHtml(key)}</span><span class="fv">${fmtScalar(val)}</span></div>`;
}

function chipRow(vals) {
  const items = (vals || []).map(pick).filter(v => v != null && v !== "");
  return items.length ? `<div class="chips">${items.map(s =>
    `<span class="badge">${escapeHtml(typeof s === "object" ? JSON.stringify(s) : s)}</span>`).join("")}</div>` : "";
}

function matchCard(m, headlineName, headlineType) {
  return `<div class="card">
    <div class="match-head">
      <span class="score">${m.composite != null ? Math.round(m.composite) : "?"}</span>
      <span class="pname">${escapeHtml(headlineName)}</span>
      <span class="badge">${escapeHtml((headlineType || "").replace("_", " "))}</span>
      <span class="badge status-${m.status}">${m.status}</span>
    </div>
    <div class="kv">
      <span>semantic ${m.semantic != null ? Number(m.semantic).toFixed(2) : "—"}</span>
      <span>sector overlap ${m.sector_overlap != null ? Number(m.sector_overlap).toFixed(2) : "—"}</span>
    </div>
    ${m.rationale_en ? `<div class="rationale"><div class="lbl">Rationale (EN)</div>${escapeHtml(m.rationale_en)}</div>` : ""}
    ${m.rationale_vi ? `<div class="rationale"><div class="lbl">Rationale (VI)</div>${escapeHtml(m.rationale_vi)}</div>` : ""}
    ${m.draft_en ? `<details><summary>Draft email (EN)</summary><pre>${escapeHtml(m.draft_en)}</pre></details>` : ""}
    ${m.draft_vi ? `<details><summary>Draft email (VI)</summary><pre>${escapeHtml(m.draft_vi)}</pre></details>` : ""}
  </div>`;
}

function relRow(e) {
  const other = e.direction === "out"
    ? (e.dst_entity_name || e.dst_name || e.dst_id)
    : (e.src_name || e.src_id);
  const resolvable = e.direction === "out" && e.dst_resolved && e.dst_id;
  const nameHtml = resolvable
    ? `<a class="lnk" data-goto="${escapeAttr(e.dst_id)}" href="#">${escapeHtml(other)}</a>`
    : `<span class="${e.dst_resolved || e.direction === "in" ? "" : "unres"}">${escapeHtml(other)}</span>`;
  const arrow = e.direction === "out" ? "→" : "←";
  return `<div class="rel"><span class="rk">${escapeHtml(e.kind)}</span>
    <span class="arrow">${arrow}</span>${nameHtml}
    ${e.source_url ? `<a class="src" href="${escapeAttr(e.source_url)}" target="_blank" rel="noopener">source ↗</a>` : ""}</div>`;
}

async function loadDetail() {
  if (!selected) return;
  let ent;
  try { ent = await j("/entities/" + encodeURIComponent(selected)); }
  catch (e) { $("detail").innerHTML = `<div class="empty">Failed to load entity: ${escapeHtml(e.message)}</div>`; return; }

  const prof = ent.profile || {};
  const isStartup = ent.type === "startup";
  const norm = prof.normalized || {};
  const seed = prof.seed || (ent.status === "ready" ? {} : prof);
  const edges = ent.edges || [];
  const desc = pick(norm.description_en) || pick(prof.description) || "";
  const website = pick(seed.hint_website) || pick(seed.website) || pick(prof.website);

  let matches = [];
  try {
    matches = await j("/matches?" + (isStartup ? "startup_id=" : "partner_id=") + encodeURIComponent(selected));
  } catch (e) { /* matches optional */ }

  // header card
  let html = `<div class="card">
    <div class="match-head">
      <span class="pname">${escapeHtml(ent.name)}</span>
      <span class="badge">${escapeHtml(ent.type.replace("_", " "))}</span>
      <span class="badge ${ent.status}">${ent.status}</span>
    </div>
    ${chipRow(norm.sectors)}
    ${desc ? `<div class="rationale">${escapeHtml(desc)}</div>` : ""}
    <div class="kv">
      ${pick(seed.country) ? `<span>📍 ${escapeHtml(pick(seed.country))}</span>` : ""}
      ${pick(norm.stage) ? `<span>stage ${escapeHtml(pick(norm.stage))}</span>` : ""}
      ${website ? `<span>🔗 <a class="lnk" href="${escapeAttr(/^https?:/.test(website) ? website : "https://" + website)}" target="_blank" rel="noopener">${escapeHtml(website)}</a></span>` : ""}
    </div>
  </div>`;

  // matching profile (normalized fields, R2)
  const looking = (norm.looking_for || []).map(pick).filter(Boolean);
  if ((norm.sectors && norm.sectors.length) || looking.length || pick(norm.description_vi)) {
    html += `<div class="card">
      <div class="subhead" style="border:0;padding:0;margin:0 0 8px">Matching profile</div>
      ${renderField("sectors", norm.sectors)}
      ${renderField("looking for", norm.looking_for)}
      ${norm.stage ? renderField("stage", norm.stage) : ""}
      ${pick(norm.description_vi) ? renderField("description (vi)", pick(norm.description_vi)) : ""}
    </div>`;
  }

  // seed facts
  const seedRows = Object.entries(seed).map(([k, v]) => renderField(k.replace(/^hint_/, ""), v)).join("");
  if (seedRows)
    html += `<div class="card"><div class="subhead" style="border:0;padding:0;margin:0 0 8px">Seed</div>${seedRows}</div>`;

  // enriched profile sections (generic, provenance-aware)
  const enrichRows = Object.entries(prof)
    .filter(([k]) => !RESERVED.has(k) && !(k in seed))
    .map(([k, v]) => renderField(k, v)).join("");
  if (enrichRows)
    html += `<div class="card"><div class="subhead" style="border:0;padding:0;margin:0 0 8px">Enriched profile</div>${enrichRows}</div>`;

  // relationships
  if (edges.length)
    html += `<div class="card"><div class="subhead" style="border:0;padding:0;margin:0 0 8px">Relationships (${edges.length})</div>
      ${edges.map(relRow).join("")}</div>`;

  // matches — ranked partners for a startup, reverse (interested startups) for a partner
  if (!matches.length) {
    html += `<div class="empty">No matches yet${isStartup ? ". Trigger a run, then start the supervisor with --drain." : " for this partner."}</div>`;
  } else {
    html += `<h2>${isStartup ? "Ranked matches" : "Matched startups"} (${matches.length})</h2>`;
    html += matches.map(m => isStartup
      ? matchCard(m, m.partner_name || m.partner_id, m.partner_type)
      : matchCard(m, m.startup_name || m.startup_id, "startup")).join("");
  }

  // raw profile
  html += `<details><summary>Raw profile JSON</summary><pre>${escapeHtml(JSON.stringify(prof, null, 2))}</pre></details>`;

  $("detail").innerHTML = html;
  $("detail").querySelectorAll("a[data-goto]").forEach(a =>
    a.onclick = (ev) => { ev.preventDefault(); selected = a.dataset.goto; loadEntities(); loadDetail(); });
}

