  return `<div class="rel"><span class="rk">${escapeHtml(e.kind)}</span>
    <span class="arrow">${arrow}</span>${nameHtml}
    ${e.source_url ? `<a class="src" href="${escapeAttr(e.source_url)}" target="_blank" rel="noopener">source ↗</a>` : ""}</div>`;
}

async function loadDetail() {
  if (!selected) return;
  let ent;
  try { ent = await j("/entities/" + encodeURIComponent(selected)); }
  catch (e) { $("detail").innerHTML = `<div class="empty">Failed to load entity: ${escapeHtml(e.message)}</div>`; return; }

  const prof = ent.profile || {};
  const isStartup = ent.type === "startup";
  const norm = prof.normalized || {};
  const seed = prof.seed || (ent.status === "ready" ? {} : prof);
  const edges = ent.edges || [];
  const desc = pick(norm.description_en) || pick(prof.description) || "";
  const website = pick(seed.hint_website) || pick(seed.website) || pick(prof.website);

  let matches = [];
  try {
    matches = await j("/matches?" + (isStartup ? "startup_id=" : "partner_id=") + encodeURIComponent(selected));
  } catch (e) { /* matches optional */ }

  // header card
  let html = `<div class="card">
    <div class="match-head">
      <span class="pname">${escapeHtml(ent.name)}</span>
      <span class="badge">${escapeHtml(ent.type.replace("_", " "))}</span>
      <span class="badge ${ent.status}">${ent.status}</span>
    </div>
    ${chipRow(norm.sectors)}
    ${desc ? `<div class="rationale">${escapeHtml(desc)}</div>` : ""}
    <div class="kv">
      ${pick(seed.country) ? `<span>📍 ${escapeHtml(pick(seed.country))}</span>` : ""}
      ${pick(norm.stage) ? `<span>stage ${escapeHtml(pick(norm.stage))}</span>` : ""}
      ${website ? `<span>🔗 <a class="lnk" href="${escapeAttr(/^https?:/.test(website) ? website : "https://" + website)}" target="_blank" rel="noopener">${escapeHtml(website)}</a></span>` : ""}
    </div>
  </div>`;

  // matching profile (normalized fields, R2)
  const looking = (norm.looking_for || []).map(pick).filter(Boolean);
  if ((norm.sectors && norm.sectors.length) || looking.length || pick(norm.description_vi)) {
    html += `<div class="card">
      <div class="subhead" style="border:0;padding:0;margin:0 0 8px">Matching profile</div>
      ${renderField("sectors", norm.sectors)}
      ${renderField("looking for", norm.looking_for)}
      ${norm.stage ? renderField("stage", norm.stage) : ""}
      ${pick(norm.description_vi) ? renderField("description (vi)", pick(norm.description_vi)) : ""}
    </div>`;
  }

  // seed facts
  const seedRows = Object.entries(seed).map(([k, v]) => renderField(k.replace(/^hint_/, ""), v)).join("");
  if (seedRows)
    html += `<div class="card"><div class="subhead" style="border:0;padding:0;margin:0 0 8px">Seed</div>${seedRows}</div>`;

  // enriched profile sections (generic, provenance-aware)
  const enrichRows = Object.entries(prof)
    .filter(([k]) => !RESERVED.has(k) && !(k in seed))
    .map(([k, v]) => renderField(k, v)).join("");
  if (enrichRows)
    html += `<div class="card"><div class="subhead" style="border:0;padding:0;margin:0 0 8px">Enriched profile</div>${enrichRows}</div>`;

  // relationships
  if (edges.length)
    html += `<div class="card"><div class="subhead" style="border:0;padding:0;margin:0 0 8px">Relationships (${edges.length})</div>
      ${edges.map(relRow).join("")}</div>`;

  // matches — ranked partners for a startup, reverse (interested startups) for a partner
  if (!matches.length) {
    html += `<div class="empty">No matches yet${isStartup ? ". Trigger a run, then start the supervisor with --drain." : " for this partner."}</div>`;
  } else {
    html += `<h2>${isStartup ? "Ranked matches" : "Matched startups"} (${matches.length})</h2>`;
    html += matches.map(m => isStartup
      ? matchCard(m, m.partner_name || m.partner_id, m.partner_type)
      : matchCard(m, m.startup_name || m.startup_id, "startup")).join("");
  }

  // raw profile
  html += `<details><summary>Raw profile JSON</summary><pre>${escapeHtml(JSON.stringify(prof, null, 2))}</pre></details>`;

  $("detail").innerHTML = html;
  $("detail").querySelectorAll("a[data-goto]").forEach(a =>
    a.onclick = (ev) => { ev.preventDefault(); selected = a.dataset.goto; loadEntities(); loadDetail(); });
}

